mapper.select:
select order_no, payment_no, tool_id, package_id, tool_name_snapshot, package_name_snapshot, package_use_count_snapshot, package_cash_amount_snapshot, package_point_amount_snapshot, package_pay_type_snapshot, order_status, grant_status, grant_time, create_time from osh_tool_purchase_record where user_id = #{userId} and delete_flag = 0
and tool_id = #{toolId}
order by create_time desc, id desc
